package spike

import (
	"context"
	"math"
	"net/http"
	"os"
	"testing"
	"time"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"
)

// TestOllamaContextWindow validates that Ollama/nomic-embed-text uses the full 8192-token context window.
// Skip if Ollama is not running.
func TestOllamaContextWindow(t *testing.T) {
	if os.Getenv("RUN_SPIKE_TESTS") == "" {
		t.Skip("Set RUN_SPIKE_TESTS=1 to run Ollama spike tests")
	}

	host := "http://localhost:11434"
	if h := os.Getenv("OLLAMA_HOST"); h != "" {
		host = h
	}

	// Check if Ollama is reachable
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()
	req, _ := http.NewRequestWithContext(ctx, "GET", host+"/api/tags", nil)
	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		t.Skipf("Ollama not reachable at %s: %v", host, err)
	}
	resp.Body.Close()

	cfg := config.EmbedderConfig{
		Backend:    "ollama",
		Model:      "nomic-embed-text:v1.5",
		Dimensions: 768,
		MaxTokens:  8192,
		Ollama:     config.OllamaConfig{Host: host},
	}

	ob := embedder.NewOllamaBackendNoHealthCheck(cfg)

	// Short text
	shortText := "Trust in claims verification"
	shortVec, err := ob.Embed(context.Background(), shortText, embedder.PurposeQuery)
	if err != nil {
		t.Fatalf("Embed short text: %v", err)
	}
	t.Logf("Short text vector: %d dims", len(shortVec))

	// Long text (~2000 tokens)
	longText := ""
	for i := 0; i < 200; i++ {
		longText += "This is a sentence that represents part of a markdown document section about trust in claims verification. "
	}
	longVec, err := ob.Embed(context.Background(), longText, embedder.PurposeIndex)
	if err != nil {
		t.Fatalf("Embed long text: %v", err)
	}

	// Compare vectors: they should differ significantly
	sim := cosineSimilarity(shortVec, longVec)
	t.Logf("Cosine similarity between short and long: %.4f", sim)

	if sim > 0.95 {
		t.Errorf("FAIL: Vectors too similar (%.4f > 0.95). Ollama may be truncating.", sim)
	} else {
		t.Logf("PASS: Vectors differ enough (%.4f < 0.95). Full context window likely used.", sim)
	}
}

func cosineSimilarity(a, b []float32) float64 {
	if len(a) != len(b) {
		return 0
	}
	var dotProduct, normA, normB float64
	for i := range a {
		dotProduct += float64(a[i]) * float64(b[i])
		normA += float64(a[i]) * float64(a[i])
		normB += float64(b[i]) * float64(b[i])
	}
	if normA == 0 || normB == 0 {
		return 0
	}
	return dotProduct / (math.Sqrt(normA) * math.Sqrt(normB))
}
